import{_ as a,a as d,b as i,c as t,d as o,e as n,f as s,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as p,c,a2 as u}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/federated-distributed-index.md","filePath":"ur/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"ur/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return p(),c("div",null,[...e[0]||(e[0]=[u('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index کئی ImgBed sites کو ایک دوسرے کے ساتھ file lists share کرنے دیتا ہے۔</p><p>سادہ الفاظ میں:</p><ul><li>آپ اپنی site کے selected folders دوسروں کے ساتھ share کر سکتے ہیں۔</li><li>آپ کسی دوسرے node میں join کر کے اس node کی shared file list اپنے admin panel میں sync کر سکتے ہیں۔</li><li>federated files بنیادی طور پر browsing، searching، اور links کھولنے کے لیے ہیں۔ یہ آپ کے اپنے storage میں دوبارہ upload نہیں ہوتیں۔</li></ul><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>کھولیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>page میں تین tabs ہیں:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>اپنا node enable کرنا، public domain confirm کرنا، shared folders منتخب کرنا، اور outbound index update کرنا</td></tr><tr><td>Nodes I Joined</td><td>دوسرے ImgBed nodes manage کرنا جن میں آپ joined ہیں</td></tr><tr><td>Nodes Joining Me</td><td>ان requests کو manage کرنا جو دوسرے owners آپ کے node میں join کرنے کے لیے بھیجتے ہیں</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Local Node</code> کھولیں۔</li><li><code>Enable</code> on کریں۔</li><li><code>Sync folders</code> کے تحت share کرنے والے folders منتخب کریں۔</li><li><code>Update Outbound Index</code> پر کلک کریں۔</li><li>اگر ImgBed domain change detect کرے، تو continue کرنے سے پہلے confirm کریں کہ current domain درست ہے۔</li></ol><p>آپ multiple sync folders منتخب کر سکتے ہیں۔</p><p>sync folder list empty ہو تو تمام folders share ہوتے ہیں۔</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>public domain وہ site URL ہے جو دوسرے nodes آپ کے node تک access کے لیے استعمال کرتے ہیں۔</p><p>ImgBed اسے automatically detect کرتا ہے۔ manually type کرنے کی ضرورت نہیں۔ پہلی بار index update کرتے وقت ImgBed پوچھتا ہے کہ current access URL production domain ہے یا نہیں۔</p><p>اگر بعد میں domains بدلیں، index update دوبارہ confirmation مانگے گا۔</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders طے کرتے ہیں کہ federation nodes کے ساتھ کون سی files share ہوں گی۔</p><p>مثلاً اگر آپ صرف یہ منتخب کریں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>تو دوسرے nodes صرف ان دو directories کی files دیکھ سکیں گے۔</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>یہ اس file list کو update کرتا ہے جسے دوسرے nodes آپ سے sync کر سکتے ہیں۔</p><p>اسے استعمال کریں جب:</p><ul><li>آپ پہلی بار federation enable کریں۔</li><li>آپ ایسی files upload کریں جو share کرنا چاہتے ہیں۔</li><li>آپ sync folders بدلیں۔</li><li>public domain بدل جائے اور اسے confirm کرنا ہو۔</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> وہ جگہ ہے جہاں آپ دوسرے nodes subscribe کرتے ہیں۔</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="کسی-دوسرے-node-میں-join-request-بھیجنا" tabindex="-1">کسی دوسرے Node میں Join Request بھیجنا <a class="header-anchor" href="#کسی-دوسرے-node-میں-join-request-بھیجنا" aria-label="Permalink to &quot;کسی دوسرے Node میں Join Request بھیجنا&quot;">​</a></h3><ol><li>دوسرے owner سے invitation link مانگیں۔</li><li>اسے input box میں paste کریں۔</li><li><code>Request to Join</code> پر کلک کریں۔</li><li>دوسرے owner کے admin panel میں approval کا انتظار کریں۔</li></ol><p>approval کے بعد node status approved ہو جائے گا۔</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> joined nodes سے file lists sync کرتا ہے۔</p><p>اسے استعمال کریں جب:</p><ul><li>دوسرے owner نے ابھی آپ کی request approve کی ہو۔</li><li>دوسرے owner بتائے کہ shared content update ہو گیا ہے۔</li><li>آپ تمام joined federation file lists refresh کرنا چاہتے ہوں۔</li></ul><p>صرف ایک node update کرنے کے لیے اس node card پر <code>Update Index</code> پر کلک کریں۔</p><p><img src="'+i+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>اگر آپ کوئی node sync نہیں کرنا چاہتے تو <code>Unsubscribe</code> پر کلک کریں۔</p><p>unsubscribe کے بعد اس node کا federated index آپ کی local site سے remove ہو جاتا ہے۔</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> وہ جگہ ہے جہاں آپ دوسروں کی requests handle کرتے ہیں۔</p><p><img src="'+t+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-بنانا" tabindex="-1">Invitation Link بنانا <a class="header-anchor" href="#invitation-link-بنانا" aria-label="Permalink to &quot;Invitation Link بنانا&quot;">​</a></h3><ol><li>یقینی بنائیں کہ local node enabled ہے۔</li><li>کم از کم ایک بار <code>Update Outbound Index</code> پر کلک کریں تاکہ ImgBed public domain confirm کرے۔</li><li><code>Nodes Joining Me</code> کھولیں۔</li><li><code>Reset Invitation Link</code> پر کلک کریں۔</li><li>invitation link copy کریں اور دوسرے owner کو بھیجیں۔</li></ol><p>اگر invitation link empty ہو تو عموماً public domain ابھی confirm نہیں ہوا۔ <code>Local Node</code> پر واپس جائیں اور <code>Update Outbound Index</code> پر کلک کریں۔</p><h3 id="join-requests-handle-کرنا" tabindex="-1">Join Requests Handle کرنا <a class="header-anchor" href="#join-requests-handle-کرنا" aria-label="Permalink to &quot;Join Requests Handle کرنا&quot;">​</a></h3><p>جب کوئی request submit کرتا ہے، وہ <code>Nodes Joining Me</code> list میں ظاہر ہوتی ہے۔</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>دوسرے node کو آپ کی shared file list sync کرنے دیتا ہے</td></tr><tr><td>Reject</td><td>join request refuse کرتا ہے</td></tr><tr><td>Delete</td><td>finished record remove کرتا ہے</td></tr><tr><td>Check Status</td><td>چیک کرتا ہے کہ دوسری side یہ relationship ابھی رکھتی ہے یا نہیں</td></tr></tbody></table><p>approval کے بعد بھی دوسری side کو <code>Update Inbound Index</code> پر کلک کرنا ہوگا، تب آپ کی shared files وہاں appear ہوں گی۔</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>relationship approve ہونے کے بعد node card پر <code>Message</code> پر کلک کریں۔</p><p>Messages صرف federation relationship کے بارے میں communication کے لیے ہیں۔ یہ files، tags، directories، یا permissions نہیں بدلتے۔</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-دیکھنا" tabindex="-1">Federated Files دیکھنا <a class="header-anchor" href="#federated-files-دیکھنا" aria-label="Permalink to &quot;Federated Files دیکھنا&quot;">​</a></h2><p>sync مکمل ہونے کے بعد admin file list پر واپس جائیں۔</p><p>page کے اوپر local files اور federated files کے درمیان switch کریں۔ federated files میں synced content browse کیا جا سکتا ہے۔</p><p>Federated files بنیادی طور پر viewing، searching، preview، اور links copy کرنے کے لیے ہیں۔ یہ local files نہیں، اس لیے آپ انہیں اپنی site سے move، delete، retag، یا backup نہیں کر سکتے۔</p><p><img src="'+s+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="relationship-record-نہ-ہونے-کی-وجہ-سے-reapply-کیوں-کہتا-ہے؟" tabindex="-1">Relationship Record نہ ہونے کی وجہ سے Reapply کیوں کہتا ہے؟ <a class="header-anchor" href="#relationship-record-نہ-ہونے-کی-وجہ-سے-reapply-کیوں-کہتا-ہے؟" aria-label="Permalink to &quot;Relationship Record نہ ہونے کی وجہ سے Reapply کیوں کہتا ہے؟&quot;">​</a></h3><p>عام طور پر اس کا مطلب ہے کہ دوسری side نے آپ کو delete کر کے record remove کر دیا ہے، اس لیے relationship نہیں مل رہی۔ نئی join request submit کریں۔</p><p><img src="'+r+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="join-کرنے-کے-بعد-files-کیوں-نہیں-دکھ-رہیں؟" tabindex="-1">Join کرنے کے بعد Files کیوں نہیں دکھ رہیں؟ <a class="header-anchor" href="#join-کرنے-کے-بعد-files-کیوں-نہیں-دکھ-رہیں؟" aria-label="Permalink to &quot;Join کرنے کے بعد Files کیوں نہیں دکھ رہیں؟&quot;">​</a></h3><p>چیک کریں:</p><ol><li>دوسرے owner نے آپ کی request approve کی ہے۔</li><li>دوسرے owner نے <code>Update Outbound Index</code> پر کلک کیا ہے۔</li><li>آپ نے <code>Update Inbound Index</code> پر کلک کیا ہے۔</li><li>دوسرے owner کے sync folders میں وہ directories شامل ہیں جو وہ share کرنا چاہتے ہیں۔</li></ol><h3 id="domain-change-detect-ہو-تو-کیا-کریں؟" tabindex="-1">Domain Change Detect ہو تو کیا کریں؟ <a class="header-anchor" href="#domain-change-detect-ہو-تو-کیا-کریں؟" aria-label="Permalink to &quot;Domain Change Detect ہو تو کیا کریں؟&quot;">​</a></h3><p>اگر آپ admin panel production domain سے کھول رہے ہیں تو confirm کریں اور continue کریں۔</p><p>اگر temporary address استعمال کر رہے ہیں تو cancel کریں، admin panel production domain سے دوبارہ کھولیں، پھر دوبارہ کوشش کریں۔</p><h3 id="empty-sync-folder-list-کا-کیا-مطلب-ہے؟" tabindex="-1">Empty Sync Folder List کا کیا مطلب ہے؟ <a class="header-anchor" href="#empty-sync-folder-list-کا-کیا-مطلب-ہے؟" aria-label="Permalink to &quot;Empty Sync Folder List کا کیا مطلب ہے؟&quot;">​</a></h3><p>empty sync folder list کا مطلب ہے تمام folders share ہیں۔</p><p>صرف کچھ directories share کرنی ہوں تو وہ folders manually select کریں۔</p><h3 id="outbound-اور-inbound-index-updates-کا-فرق" tabindex="-1">Outbound اور Inbound Index Updates کا فرق <a class="header-anchor" href="#outbound-اور-inbound-index-updates-کا-فرق" aria-label="Permalink to &quot;Outbound اور Inbound Index Updates کا فرق&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>وہ data update کرتا ہے جو دوسرے مجھ سے sync کر سکتے ہیں</td></tr><tr><td>Update Inbound Index</td><td>وہ data update کرتا ہے جو میں دوسروں سے sync کر چکا ہوں</td></tr></tbody></table>',78)])])}const _=l(h,[["render",b]]);export{k as __pageData,_ as default};
